templates.body:
defaults:
  st_mic_adc_type: external
  st_mic_channel: left
  st_mic_bits_per_sample: 32bit
  st_mic_sample_rate: "16000"

# Dedicated I2S bus for the microphone. Kept separate from any speaker bus so both
# can coexist on dual-I2S chips (ESP32 / ESP32-S3).
i2s_audio:
  - id: st_i2s_mic_bus
    i2s_lrclk_pin: ${st_mic_lrclk}
    i2s_bclk_pin: ${st_mic_bclk}

microphone:
  - platform: i2s_audio
    id: st_microphone
    i2s_audio_id: st_i2s_mic_bus
    adc_type: ${st_mic_adc_type}
    i2s_din_pin: ${st_mic_din}
    channel: ${st_mic_channel}
    bits_per_sample: ${st_mic_bits_per_sample}
    sample_rate: ${st_mic_sample_rate}

defaults:
  st_spk_dac_type: external
  st_spk_channel: mono
  st_spk_bits_per_sample: 16bit
  st_spk_sample_rate: "16000"

# Dedicated I2S bus for the speaker. Kept separate from any microphone bus so both
# can coexist on dual-I2S chips (ESP32 / ESP32-S3).
i2s_audio:
  - id: st_i2s_spk_bus
    i2s_lrclk_pin: ${st_spk_lrclk}
    i2s_bclk_pin: ${st_spk_bclk}

speaker:
  - platform: i2s_audio
    id: st_speaker
    i2s_audio_id: st_i2s_spk_bus
    dac_type: ${st_spk_dac_type}
    i2s_dout_pin: ${st_spk_dout}
    channel: ${st_spk_channel}
    bits_per_sample: ${st_spk_bits_per_sample}
    sample_rate: ${st_spk_sample_rate}

defaults:
  st_ble_scan_interval: 320ms
  st_ble_scan_window: 30ms
  st_ble_scan_duration: 5min
  st_ble_active: "true"

esp32_ble_tracker:
  id: st_ble_tracker
  scan_parameters:
    interval: ${st_ble_scan_interval}
    window: ${st_ble_scan_window}
    duration: ${st_ble_scan_duration}
    active: ${st_ble_active}

defaults:
  st_status_led_inverted: "false"

status_led:
  pin:
    number: ${st_status_led_pin}
    inverted: ${st_status_led_inverted}

defaults:
  st_ap_ssid: Fallback Hotspot

wifi:
  # Deep-merges into the user's wifi: block. Their ssid/password (station mode)
  # stay; this only adds the fallback access point.
  ap:
    ssid: ${st_ap_ssid}
    # Required var - no default. Users pass: vars: { st_ap_password: !secret ap_password }
    password: ${st_ap_password}

captive_portal:

defaults:
  st_device_comment: ""
  st_project_name: pwsh.esphome_sensor_templates
  st_project_version: 1.0.0
  st_area: ""

esphome:
  # name/friendly_name are required vars - no defaults. The user supplies them
  # via vars: { st_device_name: my-node, st_friendly_name: "My Node" }. This is
  # the whole esphome: identity block, so the top-level config must not set its
  # own esphome: name (that would deep-merge and clobber this one).
  name: ${st_device_name}
  friendly_name: ${st_friendly_name}
  comment: ${st_device_comment}
  area: ${st_area}
  project:
    name: ${st_project_name}
    version: ${st_project_version}

defaults:
  st_i2c_scan: "true"
  st_i2c_frequency: 50kHz

i2c:
  - id: st_i2c_bus
    # Required vars - no defaults. Board I2C pins vary, so the user must set them.
    sda: ${st_i2c_sda}
    scl: ${st_i2c_scl}
    scan: ${st_i2c_scan}
    frequency: ${st_i2c_frequency}

defaults:
  st_mqtt_port: "1883"
  st_mqtt_username: ""
  st_mqtt_discovery: "true"

mqtt:
  # Required var - no default. broker is the only mandatory MQTT setting.
  broker: ${st_mqtt_broker}
  port: ${st_mqtt_port}
  # Empty username = anonymous connection (broker permitting).
  username: ${st_mqtt_username}
  # Required var - no default. Users pass: vars: { st_mqtt_password: !secret mqtt_password }
  password: ${st_mqtt_password}
  discovery: ${st_mqtt_discovery}

defaults:
  st_psram_mode: quad
  st_psram_speed: 80MHz

psram:
  mode: ${st_psram_mode}
  speed: ${st_psram_speed}

defaults:
  st_safe_mode_attempts: "10"
  st_safe_mode_reboot_timeout: 5min
  st_safe_mode_boot_good_after: 1min

safe_mode:
  num_attempts: ${st_safe_mode_attempts}
  reboot_timeout: ${st_safe_mode_reboot_timeout}
  boot_is_good_after: ${st_safe_mode_boot_good_after}
  on_safe_mode:
    - logger.log: "Safe mode activated"

defaults:
  st_name_prefix: ""
  st_disabled_by_default: "false"
  st_internal: "false"

esphome:
  # esp_chip_info.h is not pulled into main.cpp by any component, so force-include
  # it for the lambda below. build_src_flags only affects the project's own src/
  # (main.cpp) and the list concatenates cleanly with flags from other templates.
  platformio_options:
    build_src_flags:
      - "-include esp_chip_info.h"
  on_boot:
    # priority -100 runs late, after all sensors/text_sensors are set up, so the
    # one-shot component.update below publishes into a live entity.
    - priority: -100
      then:
        - component.update: st_chip_info

text_sensor:
  - platform: template
    id: st_chip_info
    name: "${st_name_prefix}Chip Model"
    icon: mdi:chip
    entity_category: diagnostic
    disabled_by_default: ${st_disabled_by_default}
    internal: ${st_internal}
    # Static hardware fact - computed once and pushed from on_boot, never polled.
    update_interval: never
    lambda: |-
      esp_chip_info_t ci;
      esp_chip_info(&ci);
      const char *model;
      switch (ci.model) {
        case CHIP_ESP32:    model = "ESP32";    break;
        case CHIP_ESP32S2:  model = "ESP32-S2"; break;
        case CHIP_ESP32S3:  model = "ESP32-S3"; break;
        case CHIP_ESP32C3:  model = "ESP32-C3"; break;
        case CHIP_ESP32C6:  model = "ESP32-C6"; break;
        case CHIP_ESP32H2:  model = "ESP32-H2"; break;
        default:            model = "ESP32-family"; break;
      }
      // Decode the radio feature bitmask into a "/"-joined list.
      char feat[40];
      int n = 0;
      if (ci.features & CHIP_FEATURE_WIFI_BGN)
        n += snprintf(feat + n, sizeof(feat) - n, "%sWiFi", n ? "/" : "");
      if (ci.features & CHIP_FEATURE_BT)
        n += snprintf(feat + n, sizeof(feat) - n, "%sBT", n ? "/" : "");
      if (ci.features & CHIP_FEATURE_BLE)
        n += snprintf(feat + n, sizeof(feat) - n, "%sBLE", n ? "/" : "");
      if (ci.features & CHIP_FEATURE_IEEE802154)
        n += snprintf(feat + n, sizeof(feat) - n, "%s802.15.4", n ? "/" : "");
      // revision is major*100+minor on IDF5.
      char buf[96];
      snprintf(buf, sizeof(buf), "%s rev %u.%u, %d core%s, %s",
               model,
               (unsigned) (ci.revision / 100), (unsigned) (ci.revision % 100),
               ci.cores, ci.cores == 1 ? "" : "s", feat);
      return {std::string(buf)};

defaults:
  st_name_prefix: ""
  st_disabled_by_default: "false"
  st_internal: "false"
  st_rgbw_light_id: st_rgbw_light
  st_rgbw_light_name: "RGBW Light"
  st_rgbw_frequency: 1000Hz
  st_rgbw_max_power: "0.8"
  st_rgbw_color_interlock: "true"
  st_rgbw_restore_mode: ALWAYS_OFF

output:
  - platform: ledc
    id: ${st_rgbw_light_id}_r
    pin: ${st_rgbw_pin_r}
    frequency: ${st_rgbw_frequency}
    max_power: ${st_rgbw_max_power}
  - platform: ledc
    id: ${st_rgbw_light_id}_g
    pin: ${st_rgbw_pin_g}
    frequency: ${st_rgbw_frequency}
    max_power: ${st_rgbw_max_power}
  - platform: ledc
    id: ${st_rgbw_light_id}_b
    pin: ${st_rgbw_pin_b}
    frequency: ${st_rgbw_frequency}
    max_power: ${st_rgbw_max_power}
  - platform: ledc
    id: ${st_rgbw_light_id}_w
    pin: ${st_rgbw_pin_w}
    frequency: ${st_rgbw_frequency}
    max_power: ${st_rgbw_max_power}

light:
  - platform: rgbw
    id: ${st_rgbw_light_id}
    name: "${st_name_prefix}${st_rgbw_light_name}"
    red: ${st_rgbw_light_id}_r
    green: ${st_rgbw_light_id}_g
    blue: ${st_rgbw_light_id}_b
    white: ${st_rgbw_light_id}_w
    color_interlock: ${st_rgbw_color_interlock}
    restore_mode: ${st_rgbw_restore_mode}
    disabled_by_default: ${st_disabled_by_default}
    internal: ${st_internal}
    effects:
      - random:
          name: Slow Random
          transition_length: 5s
          update_interval: 7s
      - strobe:
          name: Strobe
      - flicker:
          name: Flicker
          alpha: 95%
          intensity: 15%

defaults:
  st_update_interval: 30s
  st_name_prefix: ""
  st_disabled_by_default: "false"
  st_internal: "false"

sensor:
  # Hidden RSSI source so this file never depends on another template's id.
  - platform: wifi_signal
    id: st_wifi_quality_rssi
    internal: true
    update_interval: ${st_update_interval}

text_sensor:
  - platform: template
    id: st_wifi_quality
    name: "${st_name_prefix}WiFi Quality"
    icon: mdi:wifi
    entity_category: diagnostic
    disabled_by_default: ${st_disabled_by_default}
    internal: ${st_internal}
    update_interval: ${st_update_interval}
    lambda: |-
      float dbm = id(st_wifi_quality_rssi).state;
      if (isnan(dbm))  return {"Unknown"};
      if (dbm > -50)   return {"Excellent"};
      if (dbm > -60)   return {"Good"};
      if (dbm > -70)   return {"Fair"};
      if (dbm > -80)   return {"Poor"};
      return {"Very Poor"};

defaults:
  st_rf_dump: rc_switch
  st_rf_tolerance: 60%
  st_rf_filter: 4us
  st_rf_idle: 4ms

remote_receiver:
  id: st_rf_receiver
  pin:
    number: ${st_rf_rx_pin}
    mode:
      input: true
  dump: ${st_rf_dump}
  # Pre-tuned for noisy 433 MHz superheterodyne receivers (ESPHome RF Bridge example values).
  tolerance: ${st_rf_tolerance}
  filter: ${st_rf_filter}
  idle: ${st_rf_idle}
